SELECT ?player ?age WHERE {
  {
    SELECT ?player(MIN(?seasonYear) AS ?firstYear) WHERE {
      ?season wdt:P154 wd:Q139257 ; wdt:P31 wd:Q10418 ; wdt:P580 ?seasonStart ; wdt:P12475 ?player .
      BIND(YEAR(?seasonStart) AS ?seasonYear)
    }
    GROUP BY ?player
  }
  ?player wdt:P569 ?birthDate .
  BIND(YEAR(?birthDate) AS ?birthYear)
  BIND(?firstYear - ?birthYear AS ?age)
}

